select 
from CMJT_FEEDBACK_ISSUE t
where 1 = 1

    and t.ID = #{bean.id}


    and t.USER_ID = #{bean.userId}


    and t.STATUS = #{bean.status}


    and t.TITLE like concat(concat('%',#{bean.title}),'%')


    and t.ORG_IDENTITY = #{bean.orgIdentity}

order by t.CREATION_DATE desc

select 
from CMJT_FEEDBACK_ISSUE t
where t.ID = #{id}

