insert into CMJT_FEEDBACK_ISSUE (
    ID, TITLE, QUESTION_CONTENT, STATUS, USER_ID, USER_NAME,
    CREATED_BY, CREATION_DATE, LAST_UPDATED_BY, LAST_UPDATE_DATE,
    ORG_IDENTITY
) values (
    #{id}, #{title}, #{questionContent}, #{status}, #{userId}, #{userName},
    #{createdBy}, #{creationDate}, #{lastUpdatedBy}, #{lastUpdateDate},
    #{orgIdentity}
)
